define i1 @icmp_eq_zext_eq_non_boolean(i32 %a) {
  %cmp = icmp eq i32 %a, 2
  %conv = zext i1 %cmp to i32
  %cmp1 = icmp eq i32 %conv, %a
  ret i1 %cmp1
}

define i1 @icmp_eq_zext_eq_one(i32 %a) {
  %cmp = icmp eq i32 %a, 1
  %conv = zext i1 %cmp to i32
